arguments.command:
cat > /tmp/test_stackalloc.cs << 'EOF'
using System;

class Program
{
    static void Main()
    {
        Span<nint> nints = stackalloc nint[4];
        nints[0] = 42;
        nints[1] = nint.MaxValue;
        Console.WriteLine($"nint span: [{nints[0]}, {nints[1]}, {nints[2]}, {nints[3]}]");
        Console.WriteLine($"nint size: {sizeof(nint)} bytes");

        Span<nuint> nuints = stackalloc nuint[4];
        nuints[0] = 99;
        nuints[1] = nuint.MaxValue;
        Console.WriteLine($"nuint span: [{nuints[0]}, {nuints[1]}, {nuints[2]}, {nuints[3]}]");
        Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");

        Console.WriteLine("Success!");
    }
}
EOF
